function ChatPortal({ conversations, children }) {
  const { div, aside, main, header, span, nav } = tags;
  const [collapsed, setCollapsed] = createSignal(false);

  return div({ class: css('_grid _h[100vh]'), style: () => `grid-template-columns:${collapsed() ? '64px' : '280px'} 1fr;grid-template-rows:52px 1fr` },
    // Conversation sidebar
    aside({ class: css('_flex _col _bgmuted _borderR'), style: 'grid-row:1/3' },
      div({ class: css('_flex _aic _jcsb _p3 _borderB') },
        !collapsed() ? span({ class: css('_heading5') }, 'Conversations') : null,
        Button({ variant: 'ghost', size: 'sm', onclick: () => setCollapsed(!collapsed()) },
          icon('panel-left')
        )
      ),
      nav({ class: css('_flex _col _gap1 _p2 _flex1 _overflow[auto]') },
        ...conversations.map(c =>
          link({ href: `/chat/${c.id}`, class: css('_flex _aic _gap2 _p2 _r2 _trans') },
            Avatar({ src: c.avatar, size: 'sm' }),
            !collapsed() ? span({ class: css('_truncate') }, c.title) : null
          )
        )
      ),
      div({ class: css('_p2 _borderT') },
        Button({ variant: 'outline', class: css('_wfull') },
          icon('plus'), !collapsed() ? ' New Chat' : null
        )
      )
    ),
    // Header
    header({ class: css('_flex _aic _jcsb _px6 _py3 _borderB _bgbg') },
      span({ class: css('_heading4') }, 'Chat'),
      div({ class: css('_flex _aic _gap2') },
        Button({ variant: 'ghost', size: 'sm' }, icon('bell')),
        Avatar({ size: 'sm' })
      )
    ),
    // Chat body with anchored input
    main({ class: css('_flex _col _overflow[hidden]') },
      div({ class: css('_flex1 _overflow[auto] _p6') },
        ...children
      )
    )
  );
}
